// BoldTrail Zapier field names confirmed from live payload inspection.
const b = $input.first().json.body || $input.first().json;

const leadName = `${b.firstname || ''} ${b.lastname || ''}`.trim();

// Buyers use street/city/state/zip; sellers use seller_* fields
const isSeller = b.is_seller === 'Yes';
const address = isSeller
  ? (b.seller_full_address || [b.seller_street, b.seller_city, b.seller_state, b.seller_zip].filter(Boolean).join(', '))
  : [b.street, b.city, b.state, b.zip].filter(Boolean).join(', ');

// Construct lead_message from available context
const msgParts = [
  b.origin ? `Source: ${b.origin}` : null,
  isSeller ? 'Interested in selling' : 'Looking to buy',
  b.referrer ? `Referrer: ${b.referrer}` : null,
  b.hashtags ? `Tags: ${b.hashtags}` : null
].filter(Boolean);

return [{
  json: {
    client_token: 'CLIENT_TOKEN_PLACEHOLDER',
    lead_name: leadName,
    email: b.email || '',
    phone: b.phone || '',
    source: b.origin || 'boldtrail',
    property_address: address,
    price_range: '',
    beds: null,
    lead_message: msgParts.join('. ') || 'BoldTrail lead',
    boldtrail_lead_id: b.leadid || null,
    is_seller: b.is_seller || 'No',
    email_status: b.email_status || '',
    on_drip: b.on_drip || 'No',
    star_rating: b.starrating || null
  }
}];
